// Dedup: track last processed build ID using static data
const staticData = $getWorkflowStaticData('global');
const lastProcessedId = staticData.lastProcessedBuildId || 0;

const builds = $input.first().json.data || [];

// Filter to only new builds
const newBuilds = builds.filter(b => b.build_id > lastProcessedId);

if (newBuilds.length === 0) {
  // No new builds — exit early
  return [];
}

// Update static data with the highest build_id we've seen
staticData.lastProcessedBuildId = Math.max(...newBuilds.map(b => b.build_id));

return newBuilds.map(b => ({ json: b }));

// Flatten sessions and attach build metadata
const items = [];
for (const item of $input.all()) {
  const sessions = item.json.data || [];
  for (const session of sessions) {
    items.push({
      json: {
        session_id: session.session_id,
        test_id: session.test_id,
        name: session.name,
        status: session.status,
        status_ind: session.status_ind,
        build_id: session.build_id,
        build_name: session.build_name,
        browser: session.browser,
        platform: session.platform,
        duration: session.duration,
        start_timestamp: session.start_timestamp,
        end_timestamp: session.end_timestamp
      }
    });
  }
}
return items;

// Merge all 3 log sources with the session metadata
const sessionData = $('Flatten Sessions').first().json;
const commandLogs = $('Fetch Command Logs').first().json;
const consoleLogs = $('Fetch Console Logs').first().json;
const networkLogs = $('Fetch Network Logs').first().json;

// Extract spec file name from session name
const sessionName = sessionData.name || '';
const specMatch = sessionName.match(/([\d._]+\w+\.spec\.js)/);
const specFile = specMatch ? specMatch[1] : sessionName;

// Truncate logs to avoid token limits
function truncate(data, maxLen = 8000) {
  const str = typeof data === 'string' ? data : JSON.stringify(data);
  return str.length > maxLen ? str.substring(0, maxLen) + '\n... [truncated]' : str;
}

return [{
  json: {
    ...sessionData,
    spec_file: specFile,
    command_logs: truncate(commandLogs),
    console_logs: truncate(consoleLogs),
    network_logs: truncate(networkLogs, 4000)
  }
}];

// Prepare context for Claude API diagnosis
const session = $('Merge Logs').first().json;
const dirListing = $('Fetch Test Source').first().json;
const jiraSearch = $('Jira Dedup Search').first().json;

// Check if existing Jira ticket found
const existingTicket = (jiraSearch.issues && jiraSearch.issues.length > 0)
  ? jiraSearch.issues[0]
  : null;

// Resolve spec file path from directory listing
// The Contents API returns an array of subdirectories (1_starlightTests, 2_bandazonTests, 3_silverProTests)
// We need to determine which subdirectory the spec belongs to based on its prefix
let specSubdir = '';
const specFile = session.spec_file || '';
if (specFile.startsWith('1')) specSubdir = '1_starlightTests';
else if (specFile.startsWith('2')) specSubdir = '2_bandazonTests';
else if (specFile.startsWith('3')) specSubdir = '3_silverProTests';

// Build the full GitHub path for later use
const fullSpecPath = specSubdir
  ? 'cypress/integration/starlight/starlightQATests/' + specSubdir + '/' + specFile
  : 'cypress/integration/starlight/starlightQATests/' + specFile;

return [{
  json: {
    ...session,
    test_source_code: 'Will be fetched via GitHub Contents API at: ' + fullSpecPath,
    full_spec_path: fullSpecPath,
    spec_subdir: specSubdir,
    existing_jira_ticket: existingTicket ? existingTicket.key : null,
    existing_jira_id: existingTicket ? existingTicket.id : null
  }
}];

// Parse Claude's response and merge with session data
const session = $('Prepare Claude Context').first().json;
const claudeResponse = $input.first().json;

let diagnosis;
try {
  const content = claudeResponse.content[0].text;
  diagnosis = JSON.parse(content);
} catch (e) {
  diagnosis = {
    root_cause: 'Claude response parse error',
    category: 'unknown',
    severity: 'medium',
    diagnosis: 'Could not parse Claude API response: ' + e.message,
    is_test_bug: false,
    is_app_bug: false,
    suggested_fix: '',
    fix_code: '',
    confidence: 0
  };
}

return [{
  json: {
    ...session,
    diagnosis: diagnosis,
    should_create_pr: diagnosis.confidence >= 0.8 && diagnosis.is_test_bug === true,
    has_existing_ticket: !!session.existing_jira_ticket
  }
}];

// GitHub Draft PR creation flow
// Step 1: Get main branch SHA
const session = $input.first().json;
const diagnosis = session.diagnosis;
const specFile = session.spec_file;
const timestamp = Date.now();
const branchName = 'qa-fix/' + specFile.replace('.spec.js', '').replace(/[^a-zA-Z0-9-_]/g, '-') + '-' + timestamp;

// We'll output the data needed for the subsequent HTTP requests
return [{
  json: {
    ...session,
    branch_name: branchName,
    timestamp: timestamp,
    repo_owner: 'ramonthedom',
    repo_name: 'LambdaCypress'
  }
}];

// Only proceed if we got the file AND have fix code
const prData = $('Prepare PR Data').first().json;
const fileData = $input.first().json;
const diagnosis = prData.diagnosis;

if (!fileData.sha || !diagnosis.fix_code) {
  // Can't create PR without file SHA or fix code
  return [{ json: { skip_pr: true, reason: 'Missing file SHA or fix code' } }];
}

// The fix_code from Claude should be the complete updated file content
// Base64 encode it for the GitHub API
const fixCode = diagnosis.fix_code;
const encoded = Buffer.from(fixCode).toString('base64');

return [{
  json: {
    ...prData,
    file_sha: fileData.sha,
    file_path: fileData.path,
    encoded_content: encoded,
    skip_pr: false
  }
}];
